use atomic_data::distributed::TaskAction;
use once_cell::sync::Lazy;
use std::collections::HashMap;

/// A compiled-in task dispatch entry.
///
/// Every function annotated with `#[task]` submits one of these via
/// `inventory::submit!` at link time. The worker binary collects them all
/// into [`TASK_REGISTRY`] at startup.
pub struct TaskEntry {
    /// Stable identifier for this task, e.g. `"mycrate::mymod::double"`.
    /// Matches the `op_id` field in [`atomic_data::distributed::TaskEnvelope`].
    pub op_id: &'static str,
    /// The dispatch function generated by the `#[task]` macro.
    /// Receives the action kind, the action config payload (e.g. fold zero),
    /// and the rkyv-encoded partition data. Returns rkyv-encoded result bytes.
    pub handler: fn(&TaskAction, &[u8], &[u8]) -> Result<Vec<u8>, String>,
}

inventory::collect!(TaskEntry);

/// Global compile-time task registry — built once at startup from all
/// `inventory::submit!(TaskEntry { ... })` calls linked into the binary.
///
/// Keyed by `op_id`. Workers call `TASK_REGISTRY.get(op_id)` to dispatch.
pub static TASK_REGISTRY: Lazy<HashMap<&'static str, fn(&TaskAction, &[u8], &[u8]) -> Result<Vec<u8>, String>>> =
    Lazy::new(|| {
        inventory::iter::<TaskEntry>
            .into_iter()
            .map(|entry| (entry.op_id, entry.handler))
            .collect()
    });

// ── Shuffle-map registry ──────────────────────────────────────────────────────

/// A compile-time shuffle-write handler registered for a specific `(K, V)` type pair.
///
/// Place `register_shuffle_map!(K, V)` in your binary once per pair used with
/// `reduce_by_key` or `group_by_key`. The worker binary collects all entries into
/// [`SHUFFLE_MAP_REGISTRY`] at startup.
///
/// # Handler contract
///
/// `handler(data, shuffle_id, map_partition_id, num_reduce_partitions)`:
/// - `data`: rkyv-encoded `Vec<(K, V)>` from the preceding pipeline ops
/// - Partitions elements by `FxHash(K) % num_reduce_partitions`
/// - Writes each bucket as bincode-encoded `Vec<(K, V)>` to `SHUFFLE_CACHE`
/// - Returns `Ok(())` on success or an error message
pub struct ShuffleMapEntry {
    /// `std::any::type_name::<(K, V)>()` — stable key identifying the type pair.
    pub type_id: &'static str,
    /// The actual write handler.
    pub handler: fn(&[u8], usize, usize, usize) -> Result<(), String>,
}

inventory::collect!(ShuffleMapEntry);

/// Global compile-time shuffle-map registry — built once at startup from all
/// `register_shuffle_map!(K, V)` calls linked into the binary.
///
/// Keyed by `type_id`. `NativeBackend` uses this when it sees `TaskAction::ShuffleMap`.
pub static SHUFFLE_MAP_REGISTRY: Lazy<HashMap<&'static str, fn(&[u8], usize, usize, usize) -> Result<(), String>>> =
    Lazy::new(|| {
        inventory::iter::<ShuffleMapEntry>
            .into_iter()
            .map(|entry| (entry.type_id, entry.handler))
            .collect()
    });

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn task_registry_is_accessible() {
        // Registry may be empty in unit tests (no #[task] functions in this crate),
        // but it must be constructible without panicking.
        let _ = &*TASK_REGISTRY;
    }

    #[test]
    fn task_registry_get_unknown_returns_none() {
        assert!(TASK_REGISTRY.get("nonexistent::op").is_none());
    }
}
